mapper.select:
SELECT count(1)
FROM core_template_category_relation cm
WHERE cm.category_id = #{categoryId}

SELECT count(1)
FROM core_template_category_relation cm
where cm.category_id != #{categoryId}
  and cm.template_id =#{templateId}

SELECT count(1) FROM core_template vt LEFT JOIN core_template_category_relation vtcm ON vt.id = vtcm.template_id WHERE vt.NAME in
#{templateName}
AND vtcm.category_id IN
#{categoryId}
and vt.id not in
#{templateId}

mapper.delete:
delete from core_template_category_relation tcm
tcm.template_id in ( select id from core_template vt where vt.name = #{templateName})
and tcm.template_id = #{templateId}

mapper.select:
select category_id
from core_template_category_relation
where template_id = #{templateId}

choose.when:
SELECT LISTAGG(category_id, ',') WITHIN GROUP (ORDER BY category_id) AS selected_subjects FROM ( SELECT DISTINCT vtcm.template_id, vtcm.category_id FROM core_template_category_relation vtcm WHERE vtcm.template_id in
#{templateId}
) GROUP BY template_id

choose.otherwise:
SELECT DISTINCT GROUP_CONCAT( DISTINCT vtcm.category_id ORDER BY vtcm.category_id ) AS selected_subjects FROM core_template_category_relation vtcm WHERE vtcm.template_id in
#{templateId}
GROUP BY vtcm.template_id
